<?php namespace App\Http\Controllers\Api\Admin; use App\Http\Controllers\Controller; use App\Models\Order; use Illuminate\Http\Request; class AdminOrderController extends Controller { public function index() { return Order::latest()->paginate(20); } public function update(Request $request, Order $order) { $order->update($request->all()); return $order; } public function show(Order $order) { return $order; } }